def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 6) / (a * b * 1.1 + 0.8)
                    term2 = np.sin(ratio * b / (a + 2)) * np.exp(-0.15 * a)
                    priority += term1 * term2
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 8
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    factor = ((ratio - p) ** 4) * np.tanh(ratio * p) / (q + 0.7)
                    priority += np.tanh(factor) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5
            if bin_cap > item * 3:
                priority -= np.sqrt(bin_cap / item) * 2.2
        elif 2 <= ratio <= 5:
            total = 0
            for r in range(1, 15):
                total += ((ratio - 2) ** r) / (r * 2) * np.cos(r * ratio * 1.3)
            priority = (total * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if i % 2 == 1:
                priority += np.sin(ratio * i * 0.9) * 1.2
        elif 1 <= ratio < 2:
            sum_s = 0
            for n in range(1, 15):
                sum_s += ((2 - ratio) ** n) / (n ** 2 + 0.8)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(22 * ratio) * 3.2
            priority = sum_s + penalty + np.exp(-2 / (ratio + 0.03))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.8) * ((ratio - 1) ** m) / (m + 0.2)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.2)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.2) + 3.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4.2) * np.cos(k * ratio * 2.3)
            priority = s + 2 / (bin_cap + 4.5)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4.5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.1)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 7.5
        elif bin_cap > item * 3.5:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if bin_cap % 2 == 1:
            for z in range(1, 3):
                priority += np.sin(ratio * (i + z)) * 0.7
        else:
            for z in range(1, 3):
                priority -= np.cos(ratio * (i + z)) * 0.7
        priorities[i] = priority
    return priorities
